        return new Source("{% extends 'base.html.twig' %}

{% block title %}Euros index{% endblock %}

{% block body %}
    <h1>Euros index</h1>

    <table class=\"table\">
        <thead>
            <tr>
                
                
                <th>Date</th>
                <th>Libelle</th>
                <th>Credit</th>
                <th>Debit</th>
                <th>Banque</th>
                
                
                <th>actions</th>
            </tr>
        </thead>
        <tbody>
        {% for euro in euros %}
            <tr>
                
                
                <td>{{ euro.date }}</td>
                <td>{{ euro.libelle }}</td>
                <td>{{ euro.credit }}</td>
                <td>{{ euro.debit }}</td>
                <td>{{ euro.banque }}</td>
                
                
                <td>
                    
                    <a href=\"{{ path('app_euros_edit', {'id': euro.id}) }}\">edit</a>
                </td>
            </tr>
        {% else %}
            <tr>
                <td colspan=\"11\">no records found</td>
            </tr>
        {% endfor %}
        </tbody>
    </table>

    <a href=\"{{ path('app_euros_new') }}\">Create new</a>
{% endblock %}
", "euros/index.html.twig", "/home/philippe/symfony/templates/euros/index.html.twig");
